sys_variable_value.value:
(function(outputs, steps, stepResult, assertEqual)
{
	var test = new x_snc_devtools.TestAPI(outputs, steps, stepResult, assertEqual);
	
	test.SetResult(true);
	
	var strCheck = 'f4ab3ebf3be44fd462bf612c95e45a63';
	
	// A table is derived from task
	var grTaskTable = x_snc_devtools.GetTableRecord('task');
	var strTableSysId = x_snc_devtools.RecordInsertOrUpdate(
		'sys_db_object',
		{
			sys_scope: 'global',
			name: 'u_test_derived_from_task'
		},
		{
			super_class: grTaskTable.sys_id
		},
		{
			label: 'Test Not Derived From Task'
		});
	test.TestCase_InstanceScanCheck(strCheck,'sys_db_object',strTableSysId,true);

	var strDictOverrideSysId = x_snc_devtools.RecordInsertOrUpdate(
		'sys_dictionary_override',
		{
			sys_scope: 'global',
			base_table: 'task',
			name: 'u_test_derived_from_task',
			element: 'number'
		},
		{
			read_only_override: true,
			read_only: true
		},
		{
		});
	test.TestCase_InstanceScanCheck(strCheck,'sys_db_object',strTableSysId,false);
	

	// A table not derived from task
	
	var strTableSysId = x_snc_devtools.RecordInsertOrUpdate(
		'sys_db_object',
		{
			sys_scope: 'global',
			name: 'u_test_not_derived_from_task'
		},
		{
			super_class: null
		},
		{
			label: 'Test Not Derived From Task'
		});

	test.TestCase_InstanceScanCheck(strCheck,'sys_db_object',strTableSysId,false);
	
	
	
	return test.GetResult();
	
})(outputs, steps, stepResult, assertEqual);
